-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 054 — Git desde Cero · M6: Git en la empresa
-- ═══════════════════════════════════════════════════════════════════
-- Unidad 5 del temario, tramo empresarial (bloques 35-38). Cubre:
-- releases, tags y hotfixes; los flujos de ramas de los equipos
-- (trunk-based, GitHub Flow, GitFlow — Diagrama 6.1); la seguridad de
-- los secretos (RETOMA lo del M2 sin repetir: rotar/revocar,
-- --force-with-lease, verificar el remoto); y cómo incorporarse a un
-- proyecto existente (README, CONTRIBUTING, contribución revisable).
-- Precisiones vinculantes: rama ≠ tag ≠ release ≠ despliegue; ningún
-- flujo de ramas es universalmente superior (se elige por contexto);
-- borrar un commit NO borra el secreto → revocar (recall del M2);
-- --force-with-lease es el force 'con cuidado', pero jamás sobre lo
-- que otros ya tienen.
-- Curso language = bash → práctica por regex + mockOutput.
-- Curso is_published = false: nada visible hasta el flip final (056).
-- Idempotente. Ejecutar DESPUÉS de 048.
-- ═══════════════════════════════════════════════════════════════════

delete from public.lessons
where module_id = (
  select m.id from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'git-desde-cero' and m.slug = 'm06-empresa'
);

insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m06-l01-releases',  'Releases, tags y hotfixes',           'leccion',  20, 1),
       ('m06-l02-flujos',    'Los flujos de ramas de los equipos',  'leccion',  20, 2),
       ('m06-l03-seguridad', 'Seguridad y errores críticos',        'leccion',  20, 3),
       ('m06-l04-proyecto',  'Incorporarse a un proyecto existente','leccion',  20, 4),
       ('m06-l05-practica',  'Práctica: preparar un release',       'practica', 20, 5),
       ('m06-x01-examen',    'Examen: Git en la empresa',           'examen',   40, 6)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'git-desde-cero' and m.slug = 'm06-empresa';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Releases, tags y hotfixes
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Cuatro palabras que se confunden","body":"En el mundo profesional se usan cuatro términos que suenan parecidos y significan cosas distintas — confundirlos genera malentendidos costosos. RAMA: una línea de desarrollo, un puntero móvil donde se trabaja (módulo 3). TAG: una marca fija sobre un commit concreto, que no se mueve (módulo 2); se usa para señalar versiones. RELEASE: una versión del software declarada lista para usarse — normalmente se apoya en un tag (v2.1.0) y añade notas de versión, artefactos compilados, un anuncio. DESPLIEGUE (deploy): el acto de PONER esa versión a correr en un servidor donde la gente la usa. La precisión vinculante: rama ≠ tag ≠ release ≠ despliegue. Un tag marca un punto; un release empaqueta y comunica una versión alrededor de ese punto; un despliegue la lleva a producción. Puedes tener un tag sin release, y un release sin desplegar todavía."}$j$),
  (2, 'texto', $j${"title":"El hotfix: la corrección que no puede esperar","body":"Escena crítica: la versión 2.1.0 está en producción y aparece un error grave —el cálculo de facturas cobra de más—. No puedes esperar al próximo release planeado ni arrastrar las funcionalidades a medias que el equipo tiene en desarrollo. Necesitas un HOTFIX: una corrección URGENTE y ACOTADA que arregla solo ese problema y sale ya. El flujo típico: se crea una rama hotfix/ partiendo de la VERSIÓN EN PRODUCCIÓN (el tag v2.1.0), NO de la rama de desarrollo (que tiene cosas sin terminar); se hace la corrección mínima; se prueba; pasa por su Pull Request (aunque sea urgente, la revisión no se salta); se integra; se etiqueta como nueva versión de PARCHE (v2.1.1 — recuerda el versionado semántico del módulo 2); y se despliega. El hotfix es cirugía de precisión: entra, arregla una cosa, sale, sin tocar nada más."}$j$),
  (3, 'ejemplo_codigo', $j${"title":"Un hotfix de principio a fin","code":"# Partir de la version EN PRODUCCION (el tag), no de desarrollo\ngit switch -c hotfix/factura-duplicada v2.1.0\n\n# La correccion minima, probada\ngit add factura.py\ngit commit -m \"Corrige el doble cobro en facturas (INC-88)\"\n\n# (PR + revision + integracion, aunque sea urgente)\n# Etiquetar la nueva version de PARCHE y publicarla\ngit tag -a v2.1.1 -m \"Hotfix: corrige el doble cobro\"\ngit push origin v2.1.1","caption":"El hotfix parte del tag de producción, corrige lo mínimo, y sube la versión de PARCHE (2.1.0 → 2.1.1).","result":{"columns":["FLUJO DEL HOTFIX"],"rows":[["hotfix/ desde el tag v2.1.0 (produccion)"],["1 commit: la correccion minima"],["PR + revision (no se salta, aunque urja)"],["tag v2.1.1 (subio el PARCHE)"],["despliegue"]],"note":"Nota que el hotfix nace del TAG de producción, no de la rama de desarrollo: así lleva SOLO la corrección, sin arrastrar trabajo a medias. Y sube el número de parche (2.1.1), porque es un arreglo compatible."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de vocabulario profesional: ¿qué distingue un TAG de un RELEASE y de un DESPLIEGUE?","options":["Son sinónimos","TAG = marca fija sobre un commit; RELEASE = una versión declarada lista (se apoya en un tag + notas/artefactos); DESPLIEGUE = poner esa versión a correr en un servidor. Rama ≠ tag ≠ release ≠ despliegue","El tag despliega y el release marca","El despliegue crea el tag"],"correctIndex":1,"feedback":{"correct":"Correcto. Un tag marca un punto; el release lo empaqueta y comunica; el despliegue lo lleva a producción. Cuatro conceptos distintos.","incorrect":"Tag (marca un commit), release (versión empaquetada alrededor del tag), despliegue (ponerla a correr): tres cosas distintas, más la rama."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué es un HOTFIX y de dónde parte su rama?","options":["Un cambio grande que parte de la rama de desarrollo","Una corrección URGENTE y acotada que parte de la VERSIÓN EN PRODUCCIÓN (el tag), no de desarrollo — así lleva solo el arreglo, sin arrastrar trabajo a medias","Un commit directo a main sin revisión","Una rama que nunca se integra"],"correctIndex":1,"feedback":{"correct":"Correcto. El hotfix nace del tag de producción para llevar SOLO la corrección; luego sube el número de parche.","incorrect":"El hotfix parte de la versión en producción (el tag), no de desarrollo — para no arrastrar funcionalidades sin terminar. Es cirugía acotada."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Tras un hotfix que corrige un error sin cambiar cómo se usa el software (de la versión 2.1.0), ¿qué versión se etiqueta?","options":["v3.0.0 (mayor)","v2.1.1 (sube el PARCHE): es una corrección compatible — versionado semántico del módulo 2","v2.2.0 (menor)","No se etiqueta"],"correctIndex":1,"feedback":{"correct":"Correcto. Arreglo compatible = sube el parche: 2.1.0 → 2.1.1. El semver del módulo 2, aplicado al hotfix.","incorrect":"Una corrección compatible sube el PARCHE (2.1.1). El menor es para funciones nuevas; el mayor para cambios que rompen."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Releases y hotfixes","points":["PRECISIÓN: rama ≠ tag ≠ release ≠ despliegue. Tag marca un commit; release empaqueta una versión; despliegue la pone a correr.","Un release se apoya en un tag (v2.1.0) y añade notas de versión y artefactos; puede existir sin desplegar aún.","HOTFIX: corrección urgente y acotada que parte de la VERSIÓN EN PRODUCCIÓN (el tag), no de desarrollo.","El hotfix pasa por su PR (la revisión no se salta ni con urgencia) y sube el número de PARCHE (2.1.0 → 2.1.1).","El hotfix es cirugía de precisión: arregla una sola cosa, sin arrastrar trabajo a medias."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-l01-releases';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Los flujos de ramas de los equipos (+ Diagrama 6.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"No hay un flujo, hay flujos","body":"Ya sabes trabajar con ramas; los equipos ADEMÁS acuerdan un FLUJO DE RAMAS (branching strategy): reglas sobre qué ramas existen, para qué sirve cada una y cómo se integran. No es capricho: define cómo docenas de personas colaboran sin pisarse. Verás tres modelos comunes, del más simple al más estructurado. Y la precisión más importante de la lección, que conviene grabar antes de conocerlos: NINGÚN flujo es universalmente superior. Cada uno resuelve un contexto distinto, y elegir el equivocado hace daño. Presentarte un flujo como 'el correcto' sería mentirte: lo profesional es entender los tres y saber cuál encaja según el equipo, la frecuencia de despliegue y las necesidades del producto."}$j$),
  (2, 'texto', $j${"title":"Los tres modelos","body":"TRUNK-BASED (basado en el tronco): todo el mundo integra a una sola rama principal (main/trunk) muy seguido, con ramas de vida cortísima (horas). Minimiza los conflictos y la divergencia (módulo 3), y es la base de la entrega continua — pero exige disciplina y buenas pruebas automáticas, porque main siempre debe estar sano. GITHUB FLOW: una rama main estable, y para cada tarea una rama corta que se abre, se revisa por Pull Request, pasa sus checks y se integra; simple y muy popular, ideal para productos web que despliegan seguido. GITFLOW: el más estructurado, con ramas de larga vida y roles fijos — main (lo que está en producción), develop (integración del trabajo en curso), y ramas feature/, release/ y hotfix/ con reglas estrictas. Potente para software con VERSIONES formales que se mantienen en paralelo (v1.x y v2.x a la vez), pero pesado para un equipo que solo quiere desplegar la web cada día."}$j$),
  (3, 'diagrama', $j${"title":"Diagrama 6.1 · Tres flujos de ramas","component":"NetworkDiagram","props":{"label":"Del más simple al más estructurado — ninguno es 'el mejor'","ancho":520,"alto":360,"grupos":[{"id":"tb","x":14,"y":24,"w":492,"h":92,"titulo":"TRUNK-BASED — una sola rama, integración muy frecuente","descripcion":"Todos integran a main/trunk seguido, con ramas de vida cortísima. Mínima divergencia; base de la entrega continua. Exige disciplina y pruebas automáticas sólidas."},{"id":"gh","x":14,"y":128,"w":492,"h":92,"titulo":"GITHUB FLOW — main + ramas cortas por PR","descripcion":"main estable; cada tarea una rama corta que entra por Pull Request revisada. Simple y popular; ideal para productos web que despliegan seguido."},{"id":"gf","x":14,"y":232,"w":492,"h":116,"titulo":"GITFLOW — ramas de larga vida con roles fijos","descripcion":"main (producción) + develop (integración) + feature/release/hotfix con reglas estrictas. Potente para versiones formales en paralelo; pesado para despliegue diario."}],"nodos":[{"id":"tbmain","x":40,"y":58,"w":110,"h":40,"titulo":"main / trunk","descripcion":"La única rama de larga vida: todos integran aquí, muy seguido."},{"id":"tbf1","x":200,"y":58,"w":120,"h":40,"titulo":"ramas de horas","descripcion":"Ramas cortísimas que nacen y se integran el mismo día: casi no divergen."},{"id":"ghmain","x":40,"y":162,"w":110,"h":40,"titulo":"main","descripcion":"Rama estable; siempre desplegable."},{"id":"ghf","x":200,"y":162,"w":120,"h":40,"titulo":"feature (PR)","descripcion":"Una rama por tarea, revisada por Pull Request antes de integrar."},{"id":"gfmain","x":30,"y":268,"w":90,"h":38,"titulo":"main","subtitulo":"producción","descripcion":"Solo lo que está en producción, etiquetado por versión."},{"id":"gfdev","x":140,"y":268,"w":90,"h":38,"titulo":"develop","descripcion":"Integración del trabajo en curso, antes de preparar un release."},{"id":"gffeat","x":250,"y":268,"w":90,"h":38,"titulo":"feature/…","descripcion":"Funcionalidades que nacen de develop."},{"id":"gfrel","x":250,"y":312,"w":90,"h":30,"titulo":"release/…","descripcion":"Preparación de una versión: estabilización antes de ir a main."},{"id":"gfhot","x":360,"y":290,"w":110,"h":38,"titulo":"hotfix/…","descripcion":"Correcciones urgentes que parten de main (producción)."}],"enlaces":[{"de":"tbf1","a":"tbmain","tipo":"flecha","etiqueta":"integra ya","descripcion":"Las ramas cortas vuelven a trunk el mismo día."},{"de":"ghf","a":"ghmain","tipo":"flecha","etiqueta":"PR","descripcion":"La feature entra a main por Pull Request revisada."},{"de":"gffeat","a":"gfdev","tipo":"flecha","descripcion":"Las features se integran a develop."},{"de":"gfrel","a":"gfmain","tipo":"flecha","descripcion":"La rama release estabiliza y pasa a main (producción)."},{"de":"gfhot","a":"gfmain","tipo":"flecha","descripcion":"El hotfix corrige directo sobre producción."}],"hint":"Compara la simplicidad de arriba con la estructura de abajo: cada una para su contexto."},"caption":"Trunk-based (una rama, integración constante), GitHub Flow (main + PRs), GitFlow (ramas de larga vida con roles). Ninguno es superior: se elige por contexto."}$j$),
  (4, 'texto', $j${"title":"Cómo se elige (el criterio, no la moda)","body":"La decisión no se toma por lo que esté de moda, sino por el CONTEXTO del equipo y el producto. Los factores que pesan: el TAMAÑO del equipo (más gente suele necesitar más estructura); la FRECUENCIA de despliegue (¿varias veces al día, o versiones cada trimestre?); los REQUISITOS REGULATORIOS (¿hace falta un registro estricto de qué se libera y cuándo?); la necesidad de MANTENER VARIAS VERSIONES vivas a la vez (v1.x para clientes viejos, v2.x para nuevos); y la COMPLEJIDAD de la liberación. Un equipo pequeño que despliega su web diez veces al día florece con trunk-based o GitHub Flow y se ahogaría con GitFlow. Una empresa que mantiene tres versiones de un producto instalado en clientes necesita la estructura de GitFlow. Lo profesional no es defender un flujo, sino leer el contexto y respetar el flujo del lugar donde trabajas: cuando entras a un equipo, adoptas SU estrategia, no impones la tuya."}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es la afirmación correcta sobre los flujos de ramas (trunk-based, GitHub Flow, GitFlow)?","options":["GitFlow es el mejor porque es el más completo","NINGUNO es universalmente superior: cada uno resuelve un contexto distinto (tamaño de equipo, frecuencia de despliegue, versiones en paralelo). Lo profesional es elegir según el contexto","Trunk-based es el único moderno","Todos son equivalentes en cualquier situación"],"correctIndex":1,"feedback":{"correct":"Correcto. Ningún flujo gana siempre: se elige por contexto. Defender uno como 'el correcto' es el error.","incorrect":"Ninguno es superior en abstracto: cada flujo encaja en un contexto. Lo profesional es leer la situación y elegir, no seguir una moda."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Un equipo pequeño mantiene una app web que despliega varias veces al día. ¿Qué flujo encaja mejor y cuál sería excesivo?","options":["GitFlow encaja; trunk-based es excesivo","Trunk-based o GitHub Flow encajan (ramas cortas, integración frecuente, despliegue continuo); GitFlow, con sus ramas de larga vida y roles fijos, sería pesado para desplegar a diario","Ninguno; hay que inventar uno","Da igual cuál"],"correctIndex":1,"feedback":{"correct":"Correcto. Despliegue diario + equipo chico → flujo ligero (trunk-based / GitHub Flow). GitFlow brilla con versiones formales en paralelo.","incorrect":"Para despliegue diario, un flujo ligero (trunk-based o GitHub Flow). GitFlow es para software con versiones formales mantenidas en paralelo."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué caracteriza a GitFlow frente a los otros dos?","options":["Que usa una sola rama","Que es el más ESTRUCTURADO: ramas de larga vida con roles fijos (main=producción, develop=integración) más feature/release/hotfix — potente para versiones formales en paralelo, pesado para despliegue continuo","Que no permite hotfixes","Que prohíbe las Pull Requests"],"correctIndex":1,"feedback":{"correct":"Correcto. GitFlow = estructura con ramas de larga vida y roles. Su fuerza (versiones paralelas) es también su peso.","incorrect":"GitFlow es el más estructurado: main + develop + feature/release/hotfix con reglas estrictas. Ideal para versiones formales, pesado para el día a día."}}$j$),
  (8, 'resumen', $j${"title":"Resumen — Flujos de ramas","points":["Un flujo de ramas es el acuerdo del equipo sobre qué ramas existen y cómo se integran.","TRUNK-BASED: una rama, integración muy frecuente, ramas de horas — base de la entrega continua.","GITHUB FLOW: main estable + ramas cortas por Pull Request — simple, ideal para web que despliega seguido.","GITFLOW: ramas de larga vida con roles (main/develop/feature/release/hotfix) — para versiones formales en paralelo.","PRECISIÓN: ninguno es superior; se elige por contexto (tamaño, despliegue, versiones, regulación). Al entrar a un equipo, adoptas SU flujo."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-l02-flujos';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Seguridad y errores críticos
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El secreto que se escapó (otra vez, en serio)","body":"En el módulo 2 lo viste; aquí lo consolidamos como lección de seguridad, porque es el error que más caro cuesta en la industria. Regla número uno: NO subir secretos al repositorio — contraseñas, tokens de API, llaves privadas, el archivo .env con las credenciales. Se previenen con .gitignore desde el minuto cero. Pero la pregunta que define a un profesional es qué hacer CUANDO YA se escapó uno. La respuesta, que se repite porque es contraintuitiva: un commit eliminado del historial NO garantiza que el secreto deje de existir. Aunque borres el commit con herramientas avanzadas, ese valor pudo clonarse a otras máquinas, quedar en respaldos, en copias del remoto, en cachés, en los logs de CI. Por eso la ÚNICA respuesta correcta ante un secreto expuesto es REVOCARLO: cambiar la contraseña, invalidar el token, generar una llave nueva. Das por comprometido lo que se filtró. Limpiar el historial es opcional y secundario; rotar la credencial es obligatorio e inmediato."}$j$),
  (2, 'texto', $j${"title":"El force, y su versión con cuidado","body":"El segundo gran peligro es reescribir historia pública — la regla de oro que ha recorrido todo el curso (amend, rebase, reset). En los remotos toma la forma de git push --force, que SOBREESCRIBE en el servidor los commits de todos con los tuyos: la forma más destructiva, porque borra el trabajo del equipo del punto de encuentro común. Existe una variante 'con cuidado': git push --force-with-lease, que solo fuerza SI nadie más publicó desde tu última sincronización — si alguien subió algo mientras tanto, se niega, protegiéndote de pisar trabajo que no habías visto. Es el force responsable para los casos legítimos (reescribir TU propia rama de feature que solo tú usas, tras un rebase local). Pero incluso con --force-with-lease, la regla no cambia: JAMÁS sobre ramas compartidas como main. Y una costumbre que salva sustos: VERIFICAR EL REMOTO antes de publicar (git remote -v), para no empujar por error al repositorio equivocado."}$j$),
  (3, 'texto', $j${"title":"Las otras salvaguardas (mención)","body":"Para cerrar el panorama de seguridad, dos herramientas que existen y conviene reconocer aunque queden fuera del nivel inicial. Las FIRMAS DE COMMITS: Git permite firmar criptográficamente tus commits para probar que de verdad los hiciste tú (y no alguien suplantando tu nombre y correo, que recuerda, son solo texto configurable). Útil en proyectos donde la autoría debe ser verificable; es contenido avanzado. Y el ESCANEO AUTOMÁTICO de secretos: muchas plataformas (y herramientas como Dependabot para dependencias vulnerables) revisan automáticamente si se coló una credencial o si usas una librería con fallos conocidos, y te avisan. Son redes de seguridad de la plataforma, no comandos de Git — mencionadas para que sepas que existen. Lo esencial de este módulo es lo anterior: no subir secretos, revocar si se escapan, y no reescribir historia pública."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Descubres que un token de API real quedó commiteado y ya se publicó al remoto. ¿La acción OBLIGATORIA e inmediata?","options":["Borrar el commit del historial y listo","REVOCAR el token (invalidarlo y generar uno nuevo): un secreto expuesto pudo copiarse a otras máquinas, respaldos y cachés — borrar el commit NO garantiza que deje de existir","Agregarlo al .gitignore","Cambiar el nombre del archivo"],"correctIndex":1,"feedback":{"correct":"Correcto. Rotar la credencial es lo obligatorio; limpiar el historial es secundario y no garantiza nada. El secreto ya salió.","incorrect":"Lo obligatorio es revocar/rotar el secreto. Borrar el commit no elimina las copias que pudieron hacerse: das por comprometido lo filtrado."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué diferencia hay entre git push --force y git push --force-with-lease?","options":["Ninguna","--force sobreescribe siempre (destructivo); --force-with-lease solo fuerza SI nadie publicó desde tu última sincronización — se niega si alguien subió algo, protegiéndote de pisar trabajo ajeno","--force-with-lease no reescribe nada","--force es el seguro"],"correctIndex":1,"feedback":{"correct":"Correcto. --force-with-lease es el force 'con cuidado': verifica que no haya trabajo nuevo antes de forzar. Aun así, jamás sobre ramas compartidas.","incorrect":"--force-with-lease comprueba que nadie haya publicado desde tu última sincronización antes de forzar; --force ignora eso y pisa todo."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuándo es aceptable usar git push --force-with-lease?","options":["Sobre main, para acelerar","Para reescribir TU propia rama de feature que solo tú usas (p. ej. tras un rebase local) — nunca sobre ramas compartidas como main, donde la regla de oro sigue intacta","Siempre que haya un rechazo","Nunca, en ningún caso"],"correctIndex":1,"feedback":{"correct":"Correcto. Legítimo en tu rama privada tras un rebase; prohibido sobre lo compartido. La regla de oro no cambia.","incorrect":"--force-with-lease es para tu propia rama privada (tras un rebase local), jamás sobre main u otra rama compartida."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Seguridad","points":["No subir secretos (contraseñas, tokens, llaves, .env): prevención con .gitignore desde el inicio.","Un secreto expuesto: REVOCARLO es obligatorio e inmediato — borrar el commit NO garantiza que deje de existir (recall del M2).","git push --force sobreescribe el trabajo del equipo: la forma más destructiva de reescribir historia pública.","--force-with-lease es el force 'con cuidado' (se niega si alguien publicó) — legítimo solo en tu rama privada, nunca en compartidas.","Verificar el remoto antes de publicar (git remote -v). Firmas de commits y escaneo automático: salvaguardas avanzadas."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-l03-seguridad';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · Incorporarse a un proyecto existente
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Tu primer día en un repositorio ajeno","body":"Casi nunca empezarás un proyecto de cero: te unirás a uno que ya lleva años y miles de commits. Saber INCORPORARTE bien —sin romper nada, contribuyendo de forma que el equipo agradezca— es una habilidad en sí misma. El primer paso es clonar (git clone) y luego LEER antes de tocar. El README te dice qué es el proyecto, cómo instalarlo y cómo correrlo. El archivo CONTRIBUTING (si existe) es aún más importante para ti: documenta las CONVENCIONES del equipo —cómo nombrar ramas, qué formato de commits usan, cómo abrir una Pull Request, qué pruebas correr—. Cada equipo tiene su cultura (lo has visto: Git no impone nombres de rama ni formato de mensajes; los fija el equipo), y CONTRIBUTING es donde esa cultura está escrita. Leerlo primero te evita el error del recién llegado que impone sus costumbres en casa ajena."}$j$),
  (2, 'texto', $j${"title":"Preparar una contribución revisable","body":"Con el proyecto entendido, el flujo para tu primer aporte reúne todo el curso. Identifica la RAMA PRINCIPAL (main o la que el proyecto use) y pártela actualizada. Crea tu rama de trabajo siguiendo LA convención del equipo (la de CONTRIBUTING, no la tuya). EJECUTA LAS PRUEBAS ANTES de tocar nada, para saber que partes de un estado sano —si algo ya fallaba, no quieres que te lo achaquen—. Haz tu cambio con commits atómicos y mensajes claros; vuelve a correr las pruebas DESPUÉS. Y una regla de oro de la buena ciudadanía: NO mezcles cambios no relacionados en tu contribución — resuelve la tarea que te tocó y solo esa; el 'ya que estaba, arreglé otras diez cosas' vuelve tu Pull Request imposible de revisar. El objetivo es una contribución REVISABLE: pequeña, enfocada, con contexto, que respeta las convenciones — la que un revisor puede entender y aprobar sin sufrir. Así se gana la confianza del equipo."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Acabas de clonar un proyecto ajeno al que te uniste. ¿Qué haces ANTES de escribir código?","options":["Empezar a cambiar cosas de inmediato","LEER: el README (qué es, cómo se instala y corre) y sobre todo CONTRIBUTING (las convenciones del equipo: nombres de rama, formato de commits, cómo abrir PR) — para adoptar SU cultura, no imponer la tuya","Borrar la rama main","Hacer push de tus preferencias"],"correctIndex":1,"feedback":{"correct":"Correcto. README y CONTRIBUTING primero: cada equipo tiene su cultura, y CONTRIBUTING es donde está escrita. Se adopta, no se impone.","incorrect":"Antes de tocar, se lee: README (cómo corre) y CONTRIBUTING (las convenciones). El recién llegado adopta la cultura del proyecto, no la suya."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué conviene ejecutar las pruebas ANTES de empezar a hacer tu cambio en un proyecto ajeno?","options":["Para hacerlas más rápidas","Para saber que partes de un estado SANO: si algo ya fallaba antes de que tocaras nada, no quieres que te lo achaquen a ti — es tu punto de referencia","Porque Git lo obliga","Para borrar las pruebas viejas"],"correctIndex":1,"feedback":{"correct":"Correcto. Correr las pruebas antes fija tu línea base: sabes qué estaba sano y qué no, antes de intervenir.","incorrect":"Ejecutarlas antes te da el estado de partida: si ya había un fallo, no es tuyo. Y las corres de nuevo después para verificar tu cambio."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué caracteriza a una contribución REVISABLE (la que el equipo agradece)?","options":["Que arregla el máximo de cosas posible de una vez","Pequeña y ENFOCADA: resuelve solo la tarea que te tocó (sin mezclar cambios no relacionados), con commits atómicos, contexto y respetando las convenciones — un revisor la entiende y aprueba sin sufrir","Que es lo más grande posible","Que no necesita revisión"],"correctIndex":1,"feedback":{"correct":"Correcto. Enfocada, atómica, con contexto y respetuosa de las convenciones: fácil de revisar = fácil de aprobar. El 'ya que estaba' arruina la PR.","incorrect":"Revisable = pequeña y enfocada en una sola tarea, sin colar cambios extra. Mezclar 'otras diez cosas' vuelve la PR imposible de revisar."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Incorporarse a un proyecto","points":["Clonar y LEER antes de tocar: README (qué es, cómo corre) y CONTRIBUTING (las convenciones del equipo).","Cada equipo tiene su cultura (Git no la impone): se adopta la del proyecto, no se impone la propia.","Partir de la rama principal actualizada; crear la rama con LA convención del equipo.","Ejecutar las pruebas ANTES (línea base sana) y DESPUÉS (verificar tu cambio).","Contribución REVISABLE: pequeña, enfocada en una sola tarea, sin mezclar cambios no relacionados. Así se gana confianza."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-l04-proyecto';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Práctica: preparar un release (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"La versión v2.1.0 del sistema de la clínica está en producción y apareció un error grave: las facturas se cobran dos veces (incidencia INC-88). Prepara el HOTFIX completo con los comandos de Git que te tocan. La corrección es un cambio mínimo en factura.py, y debe salir como versión de PARCHE. Escribe la secuencia de comandos.","instructions":["Crea la rama del hotfix partiendo de la VERSIÓN EN PRODUCCIÓN (el tag): git switch -c hotfix/doble-cobro v2.1.0.","Aplica y confirma la corrección mínima: git add factura.py y git commit -m con un mensaje que referencie la incidencia (INC-88).","Etiqueta la nueva versión de PARCHE con un tag ANOTADO: git tag -a v2.1.1 -m con un mensaje (2.1.0 → 2.1.1, porque es un arreglo compatible).","Publica el tag al remoto: git push origin v2.1.1."],"initialCode":"# Hotfix INC-88: doble cobro en facturas.\n# Produccion esta en el tag v2.1.0. La correccion sale como PARCHE.\n\n","validators":["git\\s+switch\\s+-c\\s+hotfix/doble-cobro\\s+v2\\.1\\.0","git\\s+commit\\s+-m\\s+[\"'][^\"']*inc-88","git\\s+tag\\s+-a\\s+v2\\.1\\.1\\s+-m\\s+[\"'].+[\"']","git\\s+push\\s+origin\\s+v2\\.1\\.1"],"mockOutput":{"columns":["FLUJO DEL HOTFIX — INC-88"],"rows":[["git switch -c hotfix/doble-cobro v2.1.0 → rama desde produccion"],["commit de la correccion (referencia INC-88)"],["git tag -a v2.1.1 → version de PARCHE (2.1.0 → 2.1.1)"],["git push origin v2.1.1 → tag publicado"]],"note":"El hotfix nació del tag de producción (no de desarrollo), llevó solo la corrección, subió el número de parche y publicó el tag. Cirugía de precisión: entra, arregla una cosa, sale."},"hints":["La rama del hotfix parte del TAG de producción, no de main ni develop: git switch -c hotfix/doble-cobro v2.1.0.","El commit debe referenciar la incidencia en su mensaje: incluye 'INC-88' (p. ej. \"Corrige el doble cobro (INC-88)\").","Un arreglo compatible sube el PARCHE: tag anotado v2.1.1 (git tag -a v2.1.1 -m \"...\"), y se publica con git push origin v2.1.1."],"successMessage":"¡Hotfix preparado! Partiste del tag de producción (no de desarrollo), llevaste solo la corrección con su referencia a la incidencia, subiste el número de parche (2.1.0 → 2.1.1) y publicaste el tag. Así se apaga un fuego en producción: acotado, trazable y versionado.","failMessage":"Revisa las cuatro piezas: git switch -c hotfix/doble-cobro v2.1.0 (desde el tag) · commit con 'INC-88' en el mensaje · git tag -a v2.1.1 -m \"...\" (PARCHE) · git push origin v2.1.1."}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-l05-practica';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La sexta región","body":"Byte se mueve como en casa dentro de un equipo real: versiones, flujos, seguridad y la cortesía de contribuir bien. Once preguntas guardan esta región. Las que falles volverán al final hasta que las domines. Adelante — después solo queda el proyecto."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de vocabulario: rama, tag, release y despliegue…","options":["Son cuatro nombres para lo mismo","Son cuatro cosas distintas: rama (línea de trabajo móvil), tag (marca fija sobre un commit), release (versión empaquetada alrededor de un tag), despliegue (poner esa versión a correr en un servidor)","Rama y tag son iguales; release y despliegue también","El release es una rama"],"correctIndex":1,"feedback":{"correct":"Correcto. Rama ≠ tag ≠ release ≠ despliegue: cuatro conceptos que se confunden y significan cosas distintas.","incorrect":"Rama (línea móvil), tag (marca fija), release (versión empaquetada), despliegue (ponerla a correr): cuatro cosas distintas."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Un error grave aparece en la versión 2.1.0 que está en producción. ¿De dónde parte la rama del hotfix?","options":["De la rama de desarrollo","De la VERSIÓN EN PRODUCCIÓN (el tag v2.1.0): así lleva solo la corrección, sin arrastrar el trabajo a medias que hay en desarrollo","De una rama nueva vacía","De cualquier rama"],"correctIndex":1,"feedback":{"correct":"Correcto. El hotfix nace del tag de producción para no arrastrar funcionalidades sin terminar. Cirugía acotada.","incorrect":"El hotfix parte del tag de producción, no de desarrollo — para llevar exclusivamente la corrección urgente."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Un hotfix corrige un error sin cambiar cómo se usa el software, sobre la versión 2.1.0. ¿Qué versión se etiqueta?","options":["v3.0.0","v2.1.1: sube el PARCHE (arreglo compatible), según el versionado semántico","v2.2.0","v2.1.0 otra vez"],"correctIndex":1,"feedback":{"correct":"Correcto. Corrección compatible = subir el parche: 2.1.0 → 2.1.1.","incorrect":"Un arreglo compatible sube el parche (2.1.1). Menor = función nueva; mayor = cambio que rompe."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Sobre los flujos de ramas (trunk-based, GitHub Flow, GitFlow), ¿qué es cierto?","options":["GitFlow siempre es superior","Ninguno es universalmente superior: se elige por contexto (tamaño del equipo, frecuencia de despliegue, versiones en paralelo, regulación)","Trunk-based es el único válido hoy","Son intercambiables sin consecuencias"],"correctIndex":1,"feedback":{"correct":"Correcto. Cada flujo para su contexto; defender uno como 'el correcto' es el error.","incorrect":"Ningún flujo gana siempre: la elección depende del contexto del equipo y el producto."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Un equipo pequeño despliega su app web varias veces al día. ¿Qué flujo encaja y cuál sobra?","options":["GitFlow encaja; los otros sobran","Un flujo LIGERO (trunk-based o GitHub Flow) encaja; GitFlow, con ramas de larga vida y roles fijos, sería excesivo para desplegar a diario","Ninguno funciona","Todos son iguales aquí"],"correctIndex":1,"feedback":{"correct":"Correcto. Despliegue diario + equipo chico → flujo ligero. GitFlow brilla con versiones formales en paralelo.","incorrect":"Para despliegue continuo, trunk-based o GitHub Flow. GitFlow es para software con varias versiones formales mantenidas a la vez."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"Un token de API real se coló en un commit y ya se publicó. ¿La acción obligatoria e inmediata?","options":["Borrar el commit y confiar en que desapareció","REVOCAR el token (invalidarlo, generar uno nuevo): pudo copiarse a otras máquinas, respaldos y cachés — borrar el commit NO garantiza que deje de existir","Agregarlo al .gitignore","Renombrar el archivo"],"correctIndex":1,"feedback":{"correct":"Correcto. Rotar la credencial es obligatorio; limpiar el historial es secundario y no garantiza nada.","incorrect":"Lo obligatorio es revocar el secreto. Borrar el commit no elimina las copias que ya pudieron hacerse."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hace git push --force-with-lease que lo distingue de --force?","options":["Nada, son iguales","Solo fuerza SI nadie publicó desde tu última sincronización (se niega si alguien subió algo): el force 'con cuidado' — pero aun así, nunca sobre ramas compartidas","Reescribe main sin riesgo","Sube sin necesidad de commits"],"correctIndex":1,"feedback":{"correct":"Correcto. --force-with-lease comprueba que no haya trabajo nuevo antes de forzar; --force pisa todo. Ninguno va sobre ramas compartidas.","incorrect":"--force-with-lease se niega si alguien publicó desde tu última sincronización; --force ignora eso. Aun así, jamás sobre lo compartido."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"Te unes a un proyecto ajeno ya clonado. ¿Qué haces antes de escribir código?","options":["Cambiar cosas de inmediato","LEER el README (qué es, cómo corre) y CONTRIBUTING (las convenciones del equipo), para adoptar SU cultura en vez de imponer la tuya","Borrar main","Reescribir el historial a tu gusto"],"correctIndex":1,"feedback":{"correct":"Correcto. README y CONTRIBUTING primero: el recién llegado adopta la cultura del proyecto.","incorrect":"Antes de tocar: leer README y CONTRIBUTING. Cada equipo tiene su cultura, y ahí está escrita."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué caracteriza a una contribución REVISABLE?","options":["Arreglar cuantas más cosas mejor de una vez","Pequeña y enfocada en la tarea que te tocó, con commits atómicos y sin mezclar cambios no relacionados — un revisor la entiende y aprueba sin sufrir","Ser lo más grande posible","No pasar por revisión"],"correctIndex":1,"feedback":{"correct":"Correcto. Enfocada y atómica, sin colar cambios extra. El 'ya que estaba, arreglé diez cosas' arruina la PR.","incorrect":"Revisable = pequeña, enfocada en una sola tarea, sin mezclar cambios ajenos. Fácil de revisar = fácil de aprobar."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"La 'regla de oro' del curso (no reescribir historia pública) apareció con amend, rebase, reset y push --force. ¿Cuál es su forma más destructiva y por qué?","options":["git amend, porque cambia el mensaje","git push --force sobre una rama compartida: sobreescribe en el remoto los commits de TODO el equipo, borrando su trabajo del punto de encuentro común — el daño ya no es local","git commit, porque crea historia","git clone, porque copia todo"],"correctIndex":1,"feedback":{"correct":"Correcto. amend/rebase/reset reescriben tu historia local; --force la impone al remoto compartido, borrando el trabajo de otros. Máxima consecuencia.","incorrect":"push --force sobre lo compartido es lo más destructivo: sobreescribe los commits del equipo en el remoto común. Los otros reescriben solo lo local."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta de cierre: acabas de entrar a un equipo que usa GitFlow y despliega versiones formales cada mes. Tú vienes de un equipo trunk-based que desplegaba diario. ¿Qué haces?","options":["Convences al equipo de cambiar a trunk-based, que es mejor","ADOPTAS el flujo del equipo (GitFlow): ningún flujo es universalmente superior, y este encaja con su contexto (versiones formales mantenidas). Leo su CONTRIBUTING, sigo sus convenciones de rama y release, y hago contribuciones revisables dentro de SU estrategia. La cultura del lugar se respeta, no se impone","Trabajas con tu propio flujo en paralelo","Esperas a que alguien te diga qué hacer sin leer nada"],"correctIndex":1,"feedback":{"correct":"Impecable. Ningún flujo es 'el bueno': se elige por contexto, y al entrar a un equipo adoptas el suyo. Leer CONTRIBUTING y contribuir de forma revisable dentro de su estrategia es la señal del profesional.","incorrect":"Se adopta el flujo del equipo: ninguno es superior en abstracto, y GitFlow encaja con sus versiones formales. Se lee CONTRIBUTING y se respeta su cultura, no se impone la propia."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'git-desde-cero' and l.slug = 'm06-x01-examen';
